\caption{Edge Detector for a p-Level m-Symbol Sequence} \label{alg:edge_detector} { f Input:} A $p$-level m-symbol sequence $ oldsymbol{x}_s = x_0,x_1,\ldots,x_{m-1}$ { f Output:} Arrays of positions for each transition edge $edge^{uightarrow v}$  egin{algorithmic}[1] \State Set $m' \gets m/2$ if $m$ is even, or $m' \gets (m+1)/2$ if $m$ is odd \State Initialize An array for each $edge^{u,v}$, with $u,v = 0,1,\ldots, p-1, u 
eq v$, of length $m'$ and filled with zeros \State Set invalid position marker to $0$ \State Mark $edge^{0ightarrow x_0}$ at position $1$ if $x_0 
eq 0$ \State Mark $edge^{x_{m-1}ightarrow 0}$ at position $m$ if $x_{m-1} 
eq 0$ \For{$i=1$ to $m-1$} \If{$x_{i-1} < x_i$} \State Mark $edge^{x_{i-1}ightarrow x_i}$ at position $i+1$ \ElsIf{$x_{i-1} > x_i$} \State Mark $edge^{x_{i-1}ightarrow x_{i}}$ at position $i$ \EndIf \EndFor \State return Arrays of positions for all $edge^{uightarrow v}$ \end{algorithmic}
